def insertion_sort(nums):
    """Insertion Sort."""
    for index in range(1, len(nums)):
        val = nums[index]
        left_index = index - 1
        while left_index >= 0 and nums[left_index] > val:
            nums[left_index + 1] = nums[left_index]
            left_index -= 1
        nums[left_index + 1] = val
    return nums


