def area (a, b, c):
    u = [ b[0] - a[0], b[1] - a[1], b[2] - a[2] ]
    v = [ c[0] - a[0], c[1] - a[1], c[2] - a[2] ]

    dot_uv = dot(u, v)
    cross2 = norm2(u) * norm2(v) - dot_uv * dot_uv
