import relations


def _avg_difference(npiece, side):
    if side == relations.LEFT:
        difference = npiece[:, 0] - npiece[:, 1]
    elif side == relations.RIGHT:
        difference = npiece[:, -1] - npiece[:, -2]
    elif side == relations.UP:
        difference = npiece[0, :] - npiece[1, :]
    else:
